"use client";

import { revalidateLogic, useForm } from "@tanstack/react-form";
import { useMutation } from "@tanstack/react-query";

import { Briefcase, Building, Lock, Mail, Phone, Plus, User } from "lucide-react";
import { z } from "zod";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { FormInput } from "@/components/ui/forms/form-input";
import { FormPassword } from "@/components/ui/forms/form-password";
import { FormSelect } from "@/components/ui/forms/form-select";
import { FormSwitch } from "@/components/ui/forms/form-switch";

const createUserFormSchema = z
    .object({
        firstName: z.string().min(2, "First name is required"),
        lastName: z.string().min(2, "Last name is required"),
        email: z.email("Invalid email address"),
        phone: z.string().optional(),
        jobTitle: z.string().min(2, "Job title is required"),
        role: z.string().min(1, "Please select a role"),
        department: z.string().min(1, "Please select a department"),
        password: z.string().min(8, "Password must be at least 8 characters"),
        confirmPassword: z.string(),
        active: z.boolean(),
    })
    .refine((data) => data.password === data.confirmPassword, {
        message: "Passwords do not match",
        path: ["confirmPassword"],
    });

type FormData = z.infer<typeof createUserFormSchema>;

export const CreateUserForm = () => {
    const createUserMutation = useMutation({
        mutationFn: async (value: FormData) => {
            const { confirmPassword, ...apiData } = value;
            console.log("Form submitted to API:", apiData);
            await new Promise((resolve) => setTimeout(resolve, 1000));
        },
    });

    const form = useForm({
        defaultValues: {
            firstName: "",
            lastName: "",
            email: "",
            phone: "",
            jobTitle: "",
            role: "",
            department: "",
            password: "",
            confirmPassword: "",
            active: true,
        } as FormData,
        validationLogic: revalidateLogic(),
        validators: {
            onDynamic: createUserFormSchema,
        },
        onSubmit: async ({ value }) => {
            await createUserMutation.mutateAsync(value);
        },
    });

    return (
        <form
            onSubmit={(e) => {
                e.preventDefault();
                e.stopPropagation();
                form.handleSubmit();
            }}>
            <Card className="w-full">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <User className="size-4.5" />
                        <p className="grow">Create User</p>
                        <FormSwitch name="active" containerClassName="w-fit" label="Active Account" form={form} />
                    </CardTitle>
                    <CardDescription>
                        Enter the user's details and credentials to provision a new account.
                    </CardDescription>
                </CardHeader>

                <CardContent className="grid grid-cols-1 gap-4 md:gap-5 lg:grid-cols-2">
                    <div className="space-y-4 md:space-y-5">
                        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 md:gap-5">
                            <FormInput name="firstName" label="First Name" form={form} placeholder="Jane" />
                            <FormInput name="lastName" label="Last Name" form={form} placeholder="Doe" />
                        </div>
                        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 md:gap-5">
                            <FormInput
                                name="email"
                                label="Email Address"
                                type="email"
                                form={form}
                                placeholder="jane.doe@example.com"
                                prefix={<Mail className="text-muted-foreground size-4" />}
                            />
                            <FormInput
                                name="phone"
                                label="Phone Number (Optional)"
                                type="tel"
                                form={form}
                                placeholder="+1 (555) 000-0000"
                                prefix={<Phone className="text-muted-foreground size-4" />}
                            />
                        </div>
                    </div>

                    <div className="space-y-4 md:space-y-5">
                        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 md:gap-5">
                            <FormInput
                                name="jobTitle"
                                label="Job Title"
                                form={form}
                                placeholder="e.g. Senior Developer"
                                prefix={<Briefcase className="text-muted-foreground size-4" />}
                            />
                            <FormSelect
                                name="department"
                                prefix={<Building className="text-muted-foreground size-4" />}
                                label="Department"
                                form={form}
                                placeholder="Select department"
                                options={[
                                    { label: "Engineering", value: "engineering" },
                                    { label: "Marketing", value: "marketing" },
                                    { label: "Sales", value: "sales" },
                                    { label: "Human Resources", value: "hr" },
                                ]}
                            />
                        </div>

                        <div className="grid grid-cols-1 gap-4 md:grid-cols-2 md:gap-5">
                            <FormPassword
                                name="password"
                                label="Password"
                                form={form}
                                placeholder="••••••••"
                                prefix={<Lock className="text-muted-foreground size-4" />}
                            />
                            <FormPassword
                                name="confirmPassword"
                                label="Confirm Password"
                                form={form}
                                placeholder="••••••••"
                                prefix={<Lock className="text-muted-foreground size-4" />}
                            />
                        </div>
                    </div>
                </CardContent>

                <CardFooter className="flex justify-end gap-3">
                    <Button type="button" variant="outline" onClick={() => form.reset()}>
                        Cancel
                    </Button>
                    <form.Subscribe
                        selector={(state) => [state.canSubmit, state.isSubmitting]}
                        children={([canSubmit]) => (
                            <Button nativeButton type="submit" disabled={!canSubmit || createUserMutation.isPending}>
                                {createUserMutation.isPending ? (
                                    "Creating..."
                                ) : (
                                    <>
                                        <Plus className="size-4" />
                                        Create User
                                    </>
                                )}
                            </Button>
                        )}
                    />
                </CardFooter>
            </Card>
        </form>
    );
};
